"},{"operationName":"HeaderCartQueryQuery","variables":{},"query":"query HeaderCartQueryQuery {
  viewer {
    id
    ... on Member {
      leagues {
        id
        slug
        name
        isDefault
        isElectronicPaymentsEnabled
        __typename
      }
      membershipExpires
      setting(key: "DefaultLeague")
      fee {
        message
        discount
        year
        amount
        tax
        total
        __typename
