}
"},{"operationName":"LiveStream","variables":{},"query":"query LiveStream {
  liveStream {
    __typename
    feeds {
      __typename
      ... on YoutubeLive {
        title
        description
        publishTime
        embed
        thumbnails {
          url
          height
          width
          __typename
        }
        __typename
      }
    }
  }
}
"}]

[{"operationName":"divisionLayout","variables":{"id":417530},"query":"query divisionLayout($id: Int!) {
