      id
      name
      __typename
    }
    __typename
  }
}
"}]

[{"operationName":"LeagueBox","variables":{"id":894},"query":"query LeagueBox($id: Int!) {
  viewer {
    __typename
    id
    firstName
    lastName
    emailAddress
  }
  league(id: $id) {
    id
    name
    slug
    isMine
    logo
    homePageUrl
    facebookUrl
    phone
    contacts(role: LO) {
      id
      firstName
      lastName
      phone
      __typename
    }
    __typename
  }
}
"},{"operationName":"divisionsDropdown","variables":{"id":894,"session":137},"query":"query divisionsDropdown($id: Int, $session: Int) {
