        __typename
      }
      __typename
    }
    __typename
  }
  division(id: $id) {
    id
    league {
      id
      slug
      isMine
      __typename
    }
    __typename
  }
}
"}]

[{"operationName":"divisionRosters","variables":{"id":417530},"query":"query divisionRosters($id: Int!) {
  division(id: $id) {
    id
    teams {
      isBye
      ...rosterComponent
      location {
        id
        name
        address {
          id
          name
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}

fragment rosterComponent on Team {
  id
  name
  number
  league {
    id
    slug
    __typename
  }
  division {
    id
    type
    __typename
  }
  roster {
    id
    memberNumber
    displayName
    matchesWon
    matchesPlayed
    ... on EightBallPlayer {
      pa
      ppm
      skillLevel
      __typename
    }
    ... on NineBallPlayer {
      pa
      ppm
      skillLevel
      __typename
    }
    member {
      id
      __typename
    }
    __typename
  }
  __typename
}
"}]
